e":"widget","settings":{"selected_icon":{"value":{"url":"https://dev.oganovlaw.com/wp-content/uploads/2026/02/Frame-1193-1.svg","id":221},"library":"svg"},"size":{"unit":"px","size":56,"sizes":[]},"_css_classes":"icon-open","size_mobile":{"unit":"px","size":56,"sizes":[]},"_element_width_mobile":"initial","_element_custom_width_mobile":{"unit":"px","size":40,"sizes":[]},"_flex_align_self_mobile":"center"},"elements":[],"widgetType":"icon"},{"id":"c253903","elType":"widget","settings":{"selected_icon":{"value":{"url":"https://dev.oganovlaw.com/wp-content/uploads/2026/02/Frame-1193.svg","id":214},"library":"svg"},"size":{"unit":"px","size":56,"sizes":[]},"_css_classes":"icon-closed","align_mobile":"center","size_mobile":{"unit":"px","size":56,"sizes":[]},"_element_width_mobile":"auto","_element_custom_width_mobile":{"unit":"px","size":176,"sizes":[]}},"elements":[],"widgetType":"icon"}],"isInner":true}],"isInner":true},{"id":"17dbdf9","elType":"widget","settings":{"editor":"<p data-start="1337" data-end="1538">Вы получаете право легально проживать в стране, открывать счета, вести бизнес или работать (в зависимости от типа ВНЖ).<br data-start="1456" data-end="1459" />Также открывается путь к продлению статуса и в будущем — к ПМЖ или гражданству.</p>","typography_typography":"custom","typography_font_family":"Involve","typography_font_size":{"unit":"px","size":20,"sizes":[]},"typography_font_size_mobile":{"unit":"px","size":18,"sizes":[]},"typography_font_weight":"500","text_color":"#FFFFFF99","_css_classes":"accord-hide"},"elements":[],"widgetType":"text-editor"}],"isInner":true}],"isInner":true},{"id":"c899dc1","elType":"widget","settings":{"html":"<style>
.accord-item {
  position: relative;
  overflow: hidden;
  background: transparent;
  transition: background-color 0.35s ease, border-color 0.35s ease, box-shadow 0.35s ease;
}

.accord-item.accord-item--white.is-open {
  background-color: #FFFFFF !important;
}

.accord-hide {
  max-height: 0;
  opacity: 0;
  overflow: hidden;
  margin-top: 0;
  transition:
    max-height 0.45s ease,
    opacity 0.3s ease,
    margin-top 0.45s ease;
  will-change: max-height, opacity;
}

.accord-item.is-open .accord-hide {
  opacity: 1;
  margin-top: 16px;
}

.accord-toggle {
  position: relative;
  width: 56px;
  height: 56px;
  cursor: pointer;
  flex-shrink: 0;
}

.accord-toggle .icon-closed,
.accord-toggle .icon-open {
  position: absolute !important;
  inset: 0;
  width: 56px;
  height: 56px;
  transition: opacity 0.25s ease, transform 0.25s ease;
}

.accord-toggle .icon-closed {
  opacity: 1;
  z-index: 2;
}

.accord-toggle .icon-open {
  opacity: 0;
  z-index: 3;
  pointer-events: none;
}

.accord-item.is-open .accord-toggle .icon-closed {
  opacity: 0;
  transform: scale(0.96);
}

.accord-item.is-open .accord-toggle .icon-open {
  opacity: 1;
  transform: scale(1);
}

.accord-toggle .icon-closed img,
.accord-toggle .icon-open img,
.accord-toggle .icon-closed svg,
.accord-toggle .icon-open svg {
  display: block;
  width: 100%;
  height: 100%;
}
</style>
<script>
document.addEventListener('DOMContentLoaded', function () {
  const items = document.querySelectorAll('.accord-item');
  if (!items.length) return;

  items.forEach(function (item) {
    const hidden = item.querySelector('.accord-hide');
    const toggle = item.querySelector('.accord-toggle');
    const title = item.querySelector('h2');

    if (!hidden || !toggle) return;

    const shouldTurnWhite = item.classList.contains('accord-item--white');

    hidden.style.maxHeight = '0px';
    hidden.style.opacity = '0';
    hidden.style.overflow = 'hidden';

    function closeItem(el) {
      const h = el.querySelector('.accord-hide');
      const white = el.classList.contains('accord-item--white');

      if (!h) return;

      if (h.style.maxHeight === 'none') {
        h.style.maxHeight = h.scrollHeight + 'px';
      }

      requestAnimationFrame(function () {
        el.classList.remove('is-open');

        if (white) {
          el.style.removeProperty('background-color');
        }

        h.style.maxHeight = '0px';
        h.style.opacity = '0';
      });
    }

    function toggleAccordion(e) {
      if (e) {
        e.preventDefault();
        e.stopPropagation();
      }

      const isOpen = item.classList.contains('is-open');

      if (isOpen) {
        closeItem(item);
      } else {

        /* закрываем все остальные */
        items.forEach(function (otherItem) {
          if (otherItem !== item && otherItem.classList.contains('is-open')) {
            closeItem(otherItem);
          }
        });

        item.classList.add('is-open');

        if (shouldTurnWhite) {
          item.style.setProperty('background-color', '#FFFFFF', 'important');
        }

        hidden.style.maxHeight = hidden.scrollHeight + 'px';
        hidden.style.opacity = '1';
      }
    }

    toggle.addEventListener('click', toggleAccordion);

    if (title) {
      title.addEventListener('click', toggleAccordion);
      title.style.cursor = 'pointer';
    }

    hidden.addEventListener('transitionend', function (e) {
      if (e.propertyName === 'max-height' && item.classList.contains('is-open')) {
        hidden.style.maxHeight = 'none';
      }
    });
  });

  window.addEventListener('resize', function () {
    document.querySelectorAll('.accord-item.is-open .accord-hide').forEach(function (hidden) {
      hidden.style.maxHeight = 'none';
    });
  });
});
</script>
